import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { BrowserRouter, Routes, Route, Link, useNavigate, useParams, Outlet, useLocation } from 'react-router-dom';
import { LogIn, UserPlus, Building, PlusCircle, House, MapPin, Search, Edit, Trash2, MessageSquare, Heart, LayoutDashboard, Bell, ArrowLeft, Bed, Bath, Send } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadialBarChart, RadialBar } from 'recharts';
import api, { WEBSOCKET_URL } from './api';

// --- AUTHENTICATION CONTEXT ---
const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [currentUser, setCurrentUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        try {
            const storedUser = localStorage.getItem("currentUser");
            if (storedUser) setCurrentUser(JSON.parse(storedUser));
        } catch (error) {
            console.error("Failed to parse stored user", error);
            localStorage.clear();
        }
        setLoading(false);
    }, []);

    useEffect(() => {
        if (currentUser) {
            localStorage.setItem("currentUser", JSON.stringify(currentUser));
        } else {
            localStorage.removeItem("currentUser");
            localStorage.removeItem("token");
        }
    }, [currentUser]);

    const logout = useCallback(() => setCurrentUser(null), []);

    return (
        <AuthContext.Provider value={{ currentUser, setCurrentUser, logout, loading }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

// --- DASHBOARD LAYOUT & COMPONENTS ---

const DashboardLayout = () => {
    const { currentUser, loading } = useAuth();
    const navigate = useNavigate();

    useEffect(() => {
        if (!loading && !currentUser) {
            navigate('/login');
        }
    }, [currentUser, loading, navigate]);

    if (loading || !currentUser) {
        return <div className="bg-slate-900 h-screen flex items-center justify-center text-white">Loading...</div>;
    }

    return (
        <div className="flex h-screen bg-slate-900 text-slate-100 font-sans">
            <Sidebar />
            <div className="flex-1 flex flex-col overflow-hidden">
                <Header />
                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-slate-900 p-8">
                    <Outlet />
                </main>
            </div>
        </div>
    );
};

const Sidebar = () => {
    const location = useLocation();
    const { currentUser, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };
    
    const navItems = [
        { icon: LayoutDashboard, label: "Dashboard", path: "/" },
        { icon: Building, label: "Properties", path: "/properties" },
        { icon: MessageSquare, label: "Messages", path: "/messages" },
        { icon: Heart, label: "Favorites", path: "/favorites" },
    ];

    return (
        <aside className="w-64 bg-slate-900 p-6 flex flex-col border-r border-slate-800">
            <div className="flex items-center space-x-2 mb-10">
                <Building className="h-8 w-8 text-indigo-400" />
                <span className="text-white text-2xl font-bold">Housing Hub</span>
            </div>
            <nav className="flex-1">
                <ul>
                    {navItems.map(item => (
                        <li key={item.label}>
                            <Link to={item.path} className={`flex items-center gap-3 px-4 py-3 my-2 rounded-lg transition-colors ${location.pathname.startsWith(item.path) && item.path !== '/' || location.pathname === '/' && item.path === '/' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                                <item.icon size={20} />
                                <span>{item.label}</span>
                            </Link>
                        </li>
                    ))}
                </ul>
            </nav>
            <div className="mt-auto">
                {currentUser && (
                    <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-lg mb-4">
                        <img className="h-10 w-10 rounded-full object-cover" src={`https://placehold.co/100x100/1e293b/a78bfa?text=${currentUser.email.charAt(0).toUpperCase()}`} alt="User Avatar" />
                        <div>
                            <p className="font-semibold text-white truncate">{currentUser.email}</p>
                            <p className="text-sm text-slate-400 capitalize">{currentUser.userType}</p>
                        </div>
                    </div>
                )}
                 <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 text-slate-400 hover:bg-red-900/50 hover:text-white py-2 rounded-lg transition-colors">
                    <LogIn size={16} />
                    <span>Logout</span>
                </button>
            </div>
        </aside>
    );
};

const Header = () => {
    const location = useLocation();
    const getTitle = () => {
        if (location.pathname.startsWith('/properties/')) return 'Property Details';
        if (location.pathname.startsWith('/messages')) return 'Messages';
        switch (location.pathname) {
            case '/': return 'Dashboard';
            case '/properties': return 'Property Listings';
            case '/add-property': return 'Add New Property';
            case '/favorites': return 'My Favorites';
            default: return 'Housing Hub';
        }
    };
    
    return (
        <header className="bg-slate-900/80 backdrop-blur-md p-4 flex justify-between items-center border-b border-slate-800 flex-shrink-0">
            <div>
                 <h1 className="text-2xl font-bold text-white">{getTitle()}</h1>
            </div>
            <div className="flex items-center gap-4">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                    <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                </div>
                <button className="p-2 bg-slate-800 rounded-lg border border-slate-700 hover:bg-slate-700">
                    <Bell size={20} className="text-slate-300" />
                </button>
                {useAuth().currentUser?.userType === 'landlord' && (
                    <Link to="/add-property" className="bg-indigo-600 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2 hover:bg-indigo-500 transition-colors">
                        <PlusCircle size={20} />
                        <span>New Property</span>
                    </Link>
                )}
            </div>
        </header>
    );
};

// --- PAGE COMPONENTS (VIEWS) ---

const DashboardView = () => {
    const propertyListenData = [ { name: 'Jan', uv: 400, pv: 2400 }, { name: 'Feb', uv: 300, pv: 1398 }, { name: 'Mar', uv: 200, pv: 9800 }, { name: 'Apr', uv: 278, pv: 3908 }, { name: 'May', uv: 189, pv: 4800 }, { name: 'Jun', uv: 239, pv: 3800 }, { name: 'Jul', uv: 349, pv: 4300 }, ];
    const radialChartData = [{ name: 'Occupancy', uv: 50, fill: '#818cf8' }];

    return (
        <div className="space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                    <h2 className="text-xl font-bold text-white mb-4">Featured Property</h2>
                    <div className="bg-cover bg-center p-6 rounded-lg h-64 flex flex-col justify-end" style={{ backgroundImage: "url('https://images.unsplash.com/photo-1580587771525-78b9dba3b914?q=80&w=2574&auto=format&fit=crop')" }}>
                        <div className="bg-black/50 backdrop-blur-sm p-4 rounded-md">
                            <h3 className="text-lg font-semibold text-white">Modern Villa with Pool</h3>
                            <p className="text-sm text-slate-300">123 Luxury Ave, Miami, FL</p>
                        </div>
                    </div>
                </div>
                <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 space-y-4">
                     <h2 className="text-xl font-bold text-white mb-2">Recent Listings</h2>
                     <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg">
                        <img src="https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?q=80&w=2670&auto=format&fit=crop" alt="Property" className="w-24 h-16 rounded-md object-cover" />
                        <div>
                            <p className="font-semibold text-white">Downtown Loft</p>
                            <p className="text-indigo-400 font-bold">$4,500<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                        </div>
                     </div>
                     <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg">
                        <img src="https://images.unsplash.com/photo-1448630360428-65456885c650?q=80&w=2667&auto=format&fit=crop" alt="Property" className="w-24 h-16 rounded-md object-cover" />
                        <div>
                            <p className="font-semibold text-white">Suburban House</p>
                            <p className="text-indigo-400 font-bold">$3,200<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                        </div>
                     </div>
                </div>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                    <h2 className="text-xl font-bold text-white mb-4">Property Views Analytics</h2>
                     <ResponsiveContainer width="100%" height={250}>
                        <BarChart data={propertyListenData}>
                            <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                            <XAxis dataKey="name" stroke="#9ca3af" />
                            <YAxis stroke="#9ca3af" />
                            <Tooltip contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151' }} cursor={{fill: 'rgba(129, 140, 248, 0.1)'}}/>
                            <Bar dataKey="pv" fill="#818cf8" />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 flex flex-col items-center justify-center">
                    <h2 className="text-xl font-bold text-white mb-4">Occupancy Rate</h2>
                    <ResponsiveContainer width="100%" height={250}>
                         <RadialBarChart innerRadius="70%" outerRadius="90%" data={radialChartData} startAngle={90} endAngle={-270} barSize={30}>
                            <RadialBar minAngle={15} dataKey='uv' cornerRadius={15} />
                            <text x="50%" y="50%" textAnchor="middle" dominantBaseline="middle" className="text-4xl font-bold fill-white">50%</text>
                         </RadialBarChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

const PropertiesView = () => {
    const { currentUser } = useAuth();
    const [properties, setProperties] = useState([]);
    const [favorites, setFavorites] = useState(new Set());
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const fetchData = useCallback(async () => {
        if (!currentUser) return;
        setLoading(true);
        try {
            const propsResponse = await api.get('/api/properties');
            setProperties(propsResponse.data);

            if (currentUser.userType === 'student') {
                const favsResponse = await api.get('/api/favorites');
                setFavorites(new Set(favsResponse.data.map(fav => fav.property_id)));
            }
        } catch (err) {
            setError('Failed to fetch data.');
        } finally {
            setLoading(false);
        }
    }, [currentUser]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleDelete = async (propertyId, e) => {
        e.stopPropagation(); e.preventDefault();
        if (window.confirm('Are you sure you want to delete this property?')) {
            try {
                await api.delete(`/api/properties/${propertyId}`);
                fetchData();
            } catch (err) { alert('Failed to delete property.'); }
        }
    };

    const handleToggleFavorite = async (propertyId, e) => {
        e.stopPropagation(); e.preventDefault();
        const newFavorites = new Set(favorites);
        try {
            if (favorites.has(propertyId)) {
                await api.delete(`/api/favorites/${propertyId}`);
                newFavorites.delete(propertyId);
            } else {
                await api.post('/api/favorites', { property_id: propertyId });
                newFavorites.add(propertyId);
            }
            setFavorites(newFavorites);
        } catch (err) { alert('Failed to update favorites.'); }
    };

    if (loading) return <div className="text-center text-slate-400">Loading properties...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {properties.map(prop => (
                <Link to={`/properties/${prop._id}`} key={prop._id} className="bg-slate-800/50 rounded-2xl shadow-lg border border-slate-700 overflow-hidden group hover:border-indigo-500/50 transition-all duration-300">
                    <div className="overflow-hidden h-56">
                      <img src={prop.image_url || 'https://placehold.co/400x300/1e293b/94a3b8?text=No+Image'} alt={prop.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"/>
                    </div>
                    <div className="p-6">
                        <h3 className="text-xl font-bold text-white mb-2 truncate">{prop.title}</h3>
                        <p className="text-slate-400 text-sm mb-4 flex items-center gap-2"><MapPin size={16} />{prop.address}, {prop.city}</p>
                        <div className="flex justify-between items-center">
                            <p className="text-indigo-400 text-2xl font-bold">₹{prop.price.toLocaleString()}<span className="text-sm text-slate-400 font-normal">/mo</span></p>
                            {currentUser.userType === 'landlord' && currentUser.uid === prop.landlord_id && (
                                <div className="flex items-center gap-2">
                                    <Link to={`/edit-property/${prop._id}`} onClick={(e) => e.stopPropagation()} className="p-2 bg-slate-700 rounded-md hover:bg-indigo-600 transition-colors"><Edit size={16} /></Link>
                                    <button onClick={(e) => handleDelete(prop._id, e)} className="p-2 bg-slate-700 rounded-md hover:bg-red-600 transition-colors"><Trash2 size={16} /></button>
                                </div>
                            )}
                             {currentUser.userType === 'student' && (
                                <button onClick={(e) => handleToggleFavorite(prop._id, e)} className={`p-2 rounded-md transition-colors ${favorites.has(prop._id) ? 'bg-pink-600 text-white' : 'bg-slate-700 hover:bg-pink-600/50'}`}>
                                    <Heart size={16} className={`${favorites.has(prop._id) ? 'fill-current' : ''}`} />
                                </button>
                             )}
                        </div>
                    </div>
                </Link>
            ))}
        </div>
    );
};

const AddPropertyView = () => { /* ... existing code ... */ };
const FavoritesView = () => { /* ... existing code ... */ };

const PropertyDetailsView = () => {
    const { currentUser } = useAuth();
    const navigate = useNavigate();
    const { propertyId } = useParams();
    const [property, setProperty] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [selectedImage, setSelectedImage] = useState(null);

    const handleContact = async () => {
        try {
            const response = await api.post('/api/conversations', { 
                property_id: property._id, 
                landlord_id: property.landlord_id 
            });
            navigate(`/messages/${response.data.conversationId}`);
        } catch (err) {
            alert(err.response?.data?.message || "Could not start conversation.");
        }
    };

    useEffect(() => {
        const fetchProperty = async () => {
            setLoading(true);
            try {
                const response = await api.get(`/api/properties/${propertyId}`);
                setProperty(response.data);
                if (response.data.images && response.data.images.length > 0) {
                    setSelectedImage(response.data.images[0]);
                } else if (response.data.image_url) {
                    setSelectedImage(response.data.image_url);
                }
            } catch (err) {
                setError('Failed to fetch property details.');
            } finally {
                setLoading(false);
            }
        };
        fetchProperty();
    }, [propertyId]);

    if (loading) return <div className="text-center text-slate-400">Loading details...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;
    if (!property) return <div className="text-center text-slate-400">Property not found.</div>;

    const uniqueImages = [...new Set([property.image_url, ...property.images].filter(Boolean))];

    return (
        <div className="bg-slate-800/50 p-8 rounded-2xl border border-slate-700 max-w-6xl mx-auto">
             <Link to="/properties" className="mb-6 inline-flex items-center px-4 py-2 border border-slate-600 rounded-full hover:bg-slate-700 text-slate-300 transition-colors"><ArrowLeft size={20} className="mr-2" /> Back to Listings</Link>
            <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
                <div className="lg:col-span-3">
                    <div className="mb-4">
                        <img src={selectedImage || 'https://placehold.co/800x600/1e293b/94a3b8?text=No+Image'} alt={property.title} className="w-full h-[450px] object-cover rounded-xl shadow-lg"/>
                    </div>
                    {uniqueImages.length > 1 && (
                        <div className="flex overflow-x-auto space-x-2 p-2 bg-slate-900/50 rounded-lg">
                            {uniqueImages.map((image, index) => (
                                <img key={index} src={image} alt={`Thumbnail ${index + 1}`} className={`w-24 h-20 object-cover rounded-md cursor-pointer border-2 transition-all ${selectedImage === image ? 'border-indigo-500' : 'border-transparent hover:border-slate-500'}`} onClick={() => setSelectedImage(image)}/>
                            ))}
                        </div>
                    )}
                </div>
                <div className="lg:col-span-2">
                    <h1 className="text-4xl font-extrabold text-white mb-2">{property.title}</h1>
                    <p className="text-indigo-400 text-3xl font-bold mb-6">₹{property.price.toLocaleString()}<span className="text-base text-slate-400 font-normal"> / month</span></p>
                    
                    <div className="space-y-4 text-slate-300 text-lg my-8 border-y border-slate-700 py-6">
                        <div className="flex items-center"><MapPin className="mr-3 text-indigo-400" size={20} /><span>{property.address}, {property.city}</span></div>
                        <div className="flex items-center"><House className="mr-3 text-indigo-400" size={20} /><span>{property.property_type}</span></div>
                        {property.bedrooms && <div className="flex items-center"><Bed className="mr-3 text-indigo-400" size={20} /><span>{property.bedrooms} Bedrooms</span></div>}
                        {property.bathrooms && <div className="flex items-center"><Bath className="mr-3 text-indigo-400" size={20} /><span>{property.bathrooms} Bathrooms</span></div>}
                    </div>

                    {property.description && <div className="mb-8"><h3 className="text-2xl font-bold text-white mb-3">Description</h3><p className="leading-relaxed text-slate-300">{property.description}</p></div>}
                    {property.amenities && <div className="mb-8"><h3 className="text-2xl font-bold text-white mb-3">Amenities</h3><div className="flex flex-wrap gap-3">{property.amenities.split(',').map((a, i) => <span key={i} className="px-4 py-2 bg-slate-700 text-indigo-300 rounded-full text-sm font-medium">{a.trim()}</span>)}</div></div>}
                
                    {currentUser && currentUser.userType === 'student' && property.landlord_id !== currentUser.uid && (
                        <div className="mt-8">
                            <button onClick={handleContact} className="w-full bg-green-600 text-white font-bold py-3 px-6 rounded-full shadow-lg flex items-center justify-center hover:bg-green-500 transition-colors">
                                <MessageSquare className="mr-2" /> Contact Landlord
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

const MessagesView = () => {
    const { currentUser } = useAuth();
    const { conversationId } = useParams();
    const [conversations, setConversations] = useState([]);
    const [messages, setMessages] = useState([]);
    const [newMessage, setNewMessage] = useState("");
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();
    const ws = useRef(null);
    const messagesEndRef = useRef(null);

    const activeConversation = conversations.find(c => c._id === conversationId);

    useEffect(() => {
        const fetchConversations = async () => {
            setLoading(true);
            try {
                const response = await api.get('/api/conversations');
                setConversations(response.data);
            } catch (error) {
                console.error("Failed to fetch conversations", error);
            } finally {
                setLoading(false);
            }
        };
        if(currentUser) fetchConversations();
    }, [currentUser]);

    useEffect(() => {
        if (!conversationId) return;

        const fetchMessages = async () => {
            try {
                const response = await api.get(`/api/conversations/${conversationId}/messages`);
                setMessages(response.data);
            } catch (error) {
                console.error("Failed to fetch messages", error);
            }
        };
        fetchMessages();

        if (ws.current) ws.current.close();
        ws.current = new WebSocket(WEBSOCKET_URL);

        ws.current.onopen = () => {
            const token = localStorage.getItem("token");
            ws.current.send(JSON.stringify({ type: 'auth', token, conversationId }));
        };

        ws.current.onmessage = (event) => {
            const messageData = JSON.parse(event.data);
            if (messageData.type === 'newMessage') {
                setMessages(prev => [...prev, messageData.payload]);
            }
        };

        return () => ws.current?.close();
    }, [conversationId]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const handleSendMessage = (e) => {
        e.preventDefault();
        if (!newMessage.trim() || !ws.current || ws.current.readyState !== WebSocket.OPEN) return;
        
        ws.current.send(JSON.stringify({
            type: 'message',
            payload: { conversation_id: conversationId, content: newMessage }
        }));
        setNewMessage("");
    };

    if (loading) return <div className="text-center text-slate-400">Loading conversations...</div>;

    return (
        <div className="h-[calc(100vh-10rem)] bg-slate-800/50 rounded-2xl border border-slate-700 flex">
            <div className="w-1/3 border-r border-slate-700 overflow-y-auto">
                {conversations.map(convo => {
                    const otherUser = currentUser.userType === 'student' ? convo.landlord_id : convo.student_id;
                    return (
                        <div key={convo._id} onClick={() => navigate(`/messages/${convo._id}`)} className={`p-4 cursor-pointer hover:bg-slate-700/50 transition-colors ${conversationId === convo._id ? 'bg-indigo-900/50' : ''}`}>
                            <p className="font-semibold text-white truncate">{otherUser?.email || 'Unknown User'}</p>
                            <p className="text-sm text-slate-400 truncate">{convo.property_id?.title || 'Property Deleted'}</p>
                        </div>
                    );
                })}
            </div>
            <div className="w-2/3 flex flex-col">
                {activeConversation ? (
                    <>
                        <div className="p-4 border-b border-slate-700">
                            <h3 className="font-bold text-lg text-white">{(currentUser.userType === 'student' ? activeConversation.landlord_id?.email : activeConversation.student_id?.email) || 'Unknown User'}</h3>
                            <p className="text-sm text-slate-400">{activeConversation.property_id?.title || 'Property Deleted'}</p>
                        </div>
                        <div className="flex-1 p-4 overflow-y-auto bg-slate-900/50">
                            {messages.map(msg => (
                                <div key={msg._id} className={`mb-4 flex flex-col ${String(msg.sender_id) === currentUser.uid ? 'items-end' : 'items-start'}`}>
                                    <div className={`rounded-xl px-4 py-2 max-w-md text-white ${String(msg.sender_id) === currentUser.uid ? 'bg-indigo-600' : 'bg-slate-700'}`}>{msg.content}</div>
                                </div>
                            ))}
                            <div ref={messagesEndRef} />
                        </div>
                        <form onSubmit={handleSendMessage} className="p-4 border-t border-slate-700 flex items-center">
                            <input type="text" value={newMessage} onChange={(e) => setNewMessage(e.target.value)} placeholder="Type a message..." className="flex-1 px-4 py-2 bg-slate-700 border border-slate-600 rounded-full text-white focus:ring-indigo-500 focus:border-indigo-500"/>
                            <button type="submit" className="ml-4 bg-indigo-600 text-white p-3 rounded-full hover:bg-indigo-500 transition-colors"><Send size={20} /></button>
                        </form>
                    </>
                ) : (
                    <div className="flex-1 flex items-center justify-center"><p className="text-slate-500 text-lg">Select a conversation to start chatting.</p></div>
                )}
            </div>
        </div>
    );
};

const AuthForm = ({ isLogin }) => { /* ... existing code ... */ };

// --- MAIN APP ROUTER ---
export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    <Route path="/" element={<DashboardLayout />}>
                        <Route index element={<DashboardView />} />
                        <Route path="properties" element={<PropertiesView />} />
                        <Route path="add-property" element={<AddPropertyView />} />
                        <Route path="properties/:propertyId" element={<PropertyDetailsView />} />
                        <Route path="favorites" element={<FavoritesView />} />
                        <Route path="messages" element={<MessagesView />} />
                        <Route path="messages/:conversationId" element={<MessagesView />} />
                    </Route>
                    <Route path="/login" element={<AuthForm isLogin />} />
                    <Route path="/signup" element={<AuthForm isLogin={false} />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
